// Simple default
function connect(host: string = "localhost", port: number = 5432): string {
  return `Connected to ${host}:${port}`;
}

console.log(connect());
console.log(connect("server.com"));
console.log(connect("db.com", 3306));

// Default with other params
function formatDate(
  date: Date = new Date(),
  locale: string = "en-US"
): string {
  return date.toLocaleDateString(locale);
}

// Expression as default
function createElement(tag: string = "div", text: string = ""): string {
  return `<${tag}>${text}</${tag}>`;
}
